func agentToResponse(a db.Agent) AgentResponse {
	var rc any
	if a.RuntimeConfig != nil {
		json.Unmarshal(a.RuntimeConfig, &rc)
	}
	if rc == nil {
		rc = map[string]any{}
	}

	var tools any
	if a.Tools != nil {
		json.Unmarshal(a.Tools, &tools)
	}
	if tools == nil {
		tools = []any{}
	}

	var triggers any
	if a.Triggers != nil {
