function SkillDetail({
  skill,
  onUpdate,
  onDelete,
  onBack,
}: {
  skill: Skill;
  onUpdate: (id: string, data: UpdateSkillRequest) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
  onBack?: () => void;
}) {
  const isMobile = useIsMobile();
  const [name, setName] = useState(skill.name);
  const [description, setDescription] = useState(skill.description);
  const [content, setContent] = useState(skill.content);
  const [files, setFiles] = useState<{ path: string; content: string }[]>(
    (skill.files ?? []).map((f) => ({ path: f.path, content: f.content })),
  );
  const [selectedPath, setSelectedPath] = useState(SKILL_MD);
  const [saving, setSaving] = useState(false);
  const [loadingFiles, setLoadingFiles] = useState(false);
  const [confirmDelete, setConfirmDelete] = useState(false);
  const [showAddFile, setShowAddFile] = useState(false);
  const [showFiles, setShowFiles] = useState(!isMobile);

  // Sync basic fields from store updates
  useEffect(() => {
    setName(skill.name);
    setDescription(skill.description);
    setContent(skill.content);
  }, [skill.id, skill.name, skill.description, skill.content]);

  // Fetch full skill (with files) on selection change
  useEffect(() => {
    setSelectedPath(SKILL_MD);
    setLoadingFiles(true);
    api.getSkill(skill.id).then((full) => {
      useWorkspaceStore.getState().upsertSkill(full);
      setFiles((full.files ?? []).map((f) => ({ path: f.path, content: f.content })));
    }).catch((e) => {
      toast.error(e instanceof Error ? e.message : "Failed to load skill files");
    }).finally(() => setLoadingFiles(false));
  }, [skill.id]);

  useEffect(() => {
    setShowFiles(!isMobile);
  }, [isMobile, skill.id]);

  // Build the virtual file map
  const fileMap = useMemo(() => buildFileMap(content, files), [content, files]);
  const filePaths = useMemo(() => Array.from(fileMap.keys()), [fileMap]);
  const selectedContent = fileMap.get(selectedPath) ?? "";

  const isDirty =
    name !== skill.name ||
    description !== skill.description ||
    content !== skill.content ||
    JSON.stringify(files) !==
      JSON.stringify((skill.files ?? []).map((f) => ({ path: f.path, content: f.content })));

  const handleSave = async () => {
    setSaving(true);
    try {
      await onUpdate(skill.id, {
        name: name.trim(),
        description: description.trim(),
        content,
        files: files.filter((f) => f.path.trim()),
      });
    } catch {
      // toast handled by parent
    } finally {
      setSaving(false);
    }
  };

  const handleFileContentChange = (newContent: string) => {
    if (selectedPath === SKILL_MD) {
      setContent(newContent);
    } else {
      setFiles((prev) =>
        prev.map((f) =>
          f.path === selectedPath ? { ...f, content: newContent } : f,
        ),
      );
    }
  };

  const handleSelectPath = (path: string) => {
    setSelectedPath(path);
    if (isMobile) {
      setShowFiles(false);
    }
  };

  const handleAddFile = (path: string) => {
    setFiles((prev) => [...prev, { path, content: "" }]);
    setSelectedPath(path);
    if (isMobile) {
      setShowFiles(false);
    }
  };

  const handleDeleteFile = () => {
    if (selectedPath === SKILL_MD) return;
    setFiles((prev) => prev.filter((f) => f.path !== selectedPath));
    setSelectedPath(SKILL_MD);
  };

  return (
    <div className="flex h-full min-h-0 flex-col">
      {/* Header */}
      <div className="border-b px-4 py-3">
        <div className="flex items-start justify-between gap-3">
          <div className="min-w-0 flex-1">
            <div className="flex min-w-0 items-center gap-3">
              {onBack && (
                <Button
                  variant="ghost"
                  size="sm"
                  className="-ml-2"
                  onClick={onBack}
                >
                  <ChevronLeft className="h-4 w-4" />
                  Skills
                </Button>
              )}
              <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-muted">
                <Sparkles className="h-4 w-4 text-muted-foreground" />
              </div>
              <div className="min-w-0 flex-1">
                <div className="truncate text-sm font-semibold">{skill.name}</div>
                <div className="truncate text-xs text-muted-foreground">
                  {skill.description || "Skill details"}
                </div>
              </div>
            </div>
            <div className="mt-3 grid gap-3 sm:grid-cols-2">
              <Input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="h-9 text-sm font-medium"
                placeholder="Skill name"
              />
              <Input
                type="text"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="h-9 text-sm"
                placeholder="Description"
              />
            </div>
          </div>
          <div className="ml-3 flex items-center gap-2">
            {isDirty && (
              <Button onClick={handleSave} disabled={saving || !name.trim()} size="xs">
                <Save className="h-3 w-3" />
                {saving ? "Saving..." : "Save"}
              </Button>
            )}
            <Tooltip>
              <TooltipTrigger
                render={
                  <Button
                    variant="ghost"
                    size="xs"
                    onClick={() => setConfirmDelete(true)}
                    className="text-muted-foreground hover:text-destructive"
                  >
                    <Trash2 className="h-3 w-3" />
                  </Button>
                }
              />
              <TooltipContent>Delete skill</TooltipContent>
            </Tooltip>
          </div>
        </div>
      </div>

      {/* File browser: tree + viewer */}
      {isMobile ? (
        <div className="flex flex-1 min-h-0 flex-col">
          <div className="border-b px-3 py-2">
            <div className="flex items-center justify-between gap-2">
              <button
                type="button"
                onClick={() => setShowFiles((value) => !value)}
                className="flex items-center gap-2 rounded-md px-1 py-1 text-left text-xs font-medium text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
              >
                {showFiles ? (
                  <ChevronDown className="h-3.5 w-3.5" />
                ) : (
                  <ChevronRight className="h-3.5 w-3.5" />
                )}
                Files
              </button>
              <div className="flex items-center gap-1">
                <Tooltip>
                  <TooltipTrigger
                    render={
                      <Button
                        variant="ghost"
                        size="icon-xs"
                        onClick={() => setShowAddFile(true)}
                        className="text-muted-foreground"
                      >
                        <Plus className="h-3.5 w-3.5" />
                      </Button>
                    }
                  />
                  <TooltipContent>Add file</TooltipContent>
                </Tooltip>
                {selectedPath !== SKILL_MD && (
                  <Tooltip>
                    <TooltipTrigger
                      render={
                        <Button
                          variant="ghost"
                          size="icon-xs"
                          onClick={handleDeleteFile}
                          className="text-muted-foreground hover:text-destructive"
                        >
                          <Trash2 className="h-3.5 w-3.5" />
                        </Button>
                      }
                    />
                    <TooltipContent>Delete file</TooltipContent>
                  </Tooltip>
                )}
              </div>
            </div>
            <div className="mt-1 truncate px-1 text-[11px] text-muted-foreground">
              {selectedPath}
            </div>
          </div>
          {showFiles && (
            <div className="max-h-56 shrink-0 overflow-y-auto border-b">
              {loadingFiles ? (
                <div className="space-y-2 p-3">
                  <Skeleton className="h-4 w-full" />
                  <Skeleton className="h-4 w-3/4" />
                  <Skeleton className="h-4 w-1/2" />
                </div>
              ) : (
                <FileTree
                  filePaths={filePaths}
                  selectedPath={selectedPath}
                  onSelect={handleSelectPath}
                />
              )}
            </div>
          )}
          <div className="min-h-0 flex-1">
            {loadingFiles ? (
              <div className="space-y-3 p-4">
                <Skeleton className="h-4 w-full" />
                <Skeleton className="h-4 w-5/6" />
                <Skeleton className="h-4 w-4/6" />
                <Skeleton className="h-4 w-full" />
                <Skeleton className="h-4 w-3/4" />
              </div>
            ) : (
              <FileViewer
                key={selectedPath}
                path={selectedPath}
                content={selectedContent}
                onChange={handleFileContentChange}
              />
            )}
          </div>
        </div>
      ) : (
        <div className="flex flex-1 min-h-0">
          <div className="flex w-52 shrink-0 flex-col border-r">
            <div className="flex h-10 items-center justify-between border-b px-3">
              <span className="text-xs font-medium uppercase tracking-wider text-muted-foreground">
                Files
              </span>
              <div className="flex items-center gap-1">
                <Tooltip>
                  <TooltipTrigger
                    render={
                      <Button
                        variant="ghost"
                        size="icon-xs"
                        onClick={() => setShowAddFile(true)}
                        className="text-muted-foreground"
                      >
                        <Plus className="h-3.5 w-3.5" />
                      </Button>
                    }
                  />
                  <TooltipContent>Add file</TooltipContent>
                </Tooltip>
                {selectedPath !== SKILL_MD && (
                  <Tooltip>
                    <TooltipTrigger
                      render={
                        <Button
                          variant="ghost"
                          size="icon-xs"
                          onClick={handleDeleteFile}
                          className="text-muted-foreground hover:text-destructive"
                        >
                          <Trash2 className="h-3.5 w-3.5" />
                        </Button>
                      }
                    />
                    <TooltipContent>Delete file</TooltipContent>
                  </Tooltip>
                )}
              </div>
            </div>
            <div className="flex-1 overflow-y-auto">
              {loadingFiles ? (
                <div className="space-y-2 p-3">
                  <Skeleton className="h-4 w-full" />
                  <Skeleton className="h-4 w-3/4" />
                  <Skeleton className="h-4 w-1/2" />
                </div>
              ) : (
                <FileTree
                  filePaths={filePaths}
                  selectedPath={selectedPath}
                  onSelect={handleSelectPath}
                />
              )}
            </div>
          </div>

          <div className="min-w-0 flex-1">
            {loadingFiles ? (
              <div className="space-y-3 p-4">
                <Skeleton className="h-4 w-full" />
                <Skeleton className="h-4 w-5/6" />
                <Skeleton className="h-4 w-4/6" />
                <Skeleton className="h-4 w-full" />
                <Skeleton className="h-4 w-3/4" />
              </div>
            ) : (
              <FileViewer
                key={selectedPath}
                path={selectedPath}
                content={selectedContent}
                onChange={handleFileContentChange}
              />
            )}
          </div>
        </div>
      )}

      {/* Add file dialog */}
      {showAddFile && (
        <AddFileDialog
          existingPaths={filePaths}
          onClose={() => setShowAddFile(false)}
          onAdd={handleAddFile}
        />
      )}

      {/* Delete Confirmation */}
      {confirmDelete && (
        <Dialog open onOpenChange={(v) => { if (!v) setConfirmDelete(false); }}>
          <DialogContent className="max-w-sm" showCloseButton={false}>
            <div className="flex items-center gap-3">
              <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-destructive/10">
                <AlertCircle className="h-5 w-5 text-destructive" />
              </div>
              <DialogHeader className="flex-1 gap-1">
                <DialogTitle className="text-sm font-semibold">Delete skill?</DialogTitle>
                <DialogDescription className="text-xs">
                  This will permanently delete &quot;{skill.name}&quot; and remove it from all agents.
                </DialogDescription>
              </DialogHeader>
            </div>
            <DialogFooter>
              <Button variant="ghost" onClick={() => setConfirmDelete(false)}>
                Cancel
              </Button>
              <Button
                variant="destructive"
                onClick={() => {
                  setConfirmDelete(false);
                  onDelete(skill.id);
                }}
              >
                Delete
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      )}
    </div>
  );
}

